explanation:
\textbf{Step 1: Calculate growth rate for each category}

$$\text{Growth Rate} = \frac{Q2 - Q1}{Q1} \times 100\%$$

\begin{itemize}
\item \textbf{Category A:} $\frac{198-156}{156} \times 100 = \frac{42}{156} \times 100 = 26.92\%$
\item \textbf{Category B:} $\frac{216-174}{174} \times 100 = \frac{42}{174} \times 100 = 24.14\%$
\item \textbf{Category C:} $\frac{159-132}{132} \times 100 = \frac{27}{132} \times 100 = 20.45\%$ (Below 22\%, excluded)
\item \textbf{Category D:} $\frac{234-189}{189} \times 100 = \frac{45}{189} \times 100 = 23.81\%$
\item \textbf{Category E:} $\frac{171-147}{147} \times 100 = \frac{24}{147} \times 100 = 16.33\%$ (Below 22\%, excluded)
\end{itemize}

\textbf{Step 2: Identify qualifying categories (growth $> 22\%$) and compute excess above 22\%}

\begin{itemize}
\item \textbf{Category A:} $26.92 - 22 = 4.92\%$ \quad (Highest excess)
\item \textbf{Category B:} $24.14 - 22 = 2.14\%$ \quad (\textbf{Second-highest excess})
\item \textbf{Category D:} $23.81 - 22 = 1.81\%$ \quad (Third)
\end{itemize}

\textbf{Step 3: Compute total excess and proportional bonus for Category B (second-highest)}

$$\text{Total Excess} = 4.92 + 2.14 + 1.81 = 8.87\%$$

$$\text{Bonus for Category B} = \frac{2.14}{8.87} \times 45 = 0.2413 \times 45 \approx \textbf{Rs.~10.86 lakhs}$$

\textbf{Verification of all bonuses:}
\begin{itemize}
\item Category A bonus: $\frac{4.92}{8.87} \times 45 \approx 24.95$ lakhs
\item Category B bonus: $\frac{2.14}{8.87} \times 45 \approx 10.86$ lakhs
\item Category D bonus: $\frac{1.81}{8.87} \times 45 \approx 9.19$ lakhs
\item Total: $24.95 + 10.86 + 9.19 = 45$ lakhs \checkmark
\end{itemize}

\textbf{Answer: Rs.~10.8 lakhs} $\approx$ Option A.

